import { test, expect } from '@playwright/test';

test('login page renders', async ({ page }) => {
  await page.goto('/login');
  await expect(page.locator('h1')).toHaveText('Sign In');
});

// @prod-safe
import { test, expect } from '@playwright/test';

test('create matter via API', async ({ page, request }) => {
  await page.goto('/matters/new');
  await page.request.post('/api/matters', { data: { client: 'Jane' } });
  await expect(page.locator('.success-toast')).toBeVisible();
});

// @not-prod-safe
import { test, expect } from '@playwright/test';

test('upload document', async ({ page }) => {
  await page.goto('/matters/123/documents');
  await page.setInputFiles('input[type=file]', '/tmp/doc.pdf');
  await expect(page.locator('.uploaded-doc')).toBeVisible();
});

// @prod-safe
import { test, expect } from '@playwright/test';

test('dashboard renders all panels', async ({ page }) => {
  await page.goto('/dashboard');
  await expect(page.locator('[data-testid=matter-count]')).toBeVisible();
  await expect(page.locator('[data-testid=person-count]')).toBeVisible();
});

